import React, { useState, useEffect, useCallback } from 'react';
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  Chip,
  IconButton,
  Divider,
  Alert,
  Snackbar,
  Stack,
  Accordion,
  AccordionSummary,
  AccordionDetails,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Tooltip,
  Grid,
} from '@mui/material';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import AddIcon from '@mui/icons-material/Add';
import DeleteIcon from '@mui/icons-material/Delete';
import EditIcon from '@mui/icons-material/Edit';
import SaveIcon from '@mui/icons-material/Save';
import { nanoid } from 'nanoid';
import { useBrandStore } from '@/shared/stores/brandStore';
import { useCurrentBrand } from '@/shared/hooks/useCurrentBrand';
import type {
  Brand,
  Product,
  BrandCompetitor,
  BrandKeywords,
  ContentGuidelines,
} from '@/shared/types/brand';

/** Product form dialog */
const ProductDialog: React.FC<{
  open: boolean;
  product: Product | null;
  onClose: () => void;
  onSave: (product: Product) => void;
}> = ({ open, product, onClose, onSave }) => {
  const [form, setForm] = useState<Product>({
    name: '',
    sku: '',
    price: 0,
    unit: '元',
    coreIngredients: [],
    targetUsers: [],
    sellingPoints: [],
    status: 'active',
  });

  useEffect(() => {
    if (product) {
      setForm({ ...product });
    } else {
      setForm({
        name: '',
        sku: '',
        price: 0,
        unit: '元',
        coreIngredients: [],
        targetUsers: [],
        sellingPoints: [],
        status: 'active',
      });
    }
  }, [product, open]);

  const update = (field: keyof Product, value: unknown) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  const handleListStr = (
    field: 'coreIngredients' | 'targetUsers' | 'sellingPoints',
    value: string,
  ) => {
    update(
      field,
      value
        .split(/[,，]/)
        .map((s) => s.trim())
        .filter(Boolean),
    );
  };

  return (
    <Dialog open={open} onClose={onClose} maxWidth="sm" fullWidth>
      <DialogTitle>{product ? '编辑产品' : '添加产品'}</DialogTitle>
      <DialogContent>
        <Stack spacing={2} sx={{ pt: 1 }}>
          <TextField
            label="产品名称"
            value={form.name}
            onChange={(e) => update('name', e.target.value)}
            fullWidth
            required
          />
          <TextField
            label="SKU"
            value={form.sku}
            onChange={(e) => update('sku', e.target.value)}
            fullWidth
          />
          <Box sx={{ display: 'flex', gap: 2 }}>
            <TextField
              label="价格"
              type="number"
              value={form.price}
              onChange={(e) => update('price', Number(e.target.value))}
              sx={{ flex: 2 }}
            />
            <TextField
              label="单位"
              value={form.unit}
              onChange={(e) => update('unit', e.target.value)}
              sx={{ flex: 1 }}
            />
          </Box>
          <TextField
            label="核心成分（逗号分隔）"
            value={(form.coreIngredients || []).join('、')}
            onChange={(e) => handleListStr('coreIngredients', e.target.value)}
            fullWidth
            helperText="例如：烟酰胺、玻尿酸、维生素C"
          />
          <TextField
            label="目标用户（逗号分隔）"
            value={(form.targetUsers || []).join('、')}
            onChange={(e) => handleListStr('targetUsers', e.target.value)}
            fullWidth
            helperText="例如：油性肌肤、25-35岁女性"
          />
          <TextField
            label="卖点（逗号分隔）"
            value={(form.sellingPoints || []).join('、')}
            onChange={(e) => handleListStr('sellingPoints', e.target.value)}
            fullWidth
            helperText="例如：控油不拔干、温和不刺激"
          />
          <TextField
            label="状态"
            value={form.status}
            onChange={(e) => update('status', e.target.value)}
            fullWidth
          />
        </Stack>
      </DialogContent>
      <DialogActions>
        <Button onClick={onClose}>取消</Button>
        <Button
          onClick={() => onSave(form)}
          variant="contained"
          disabled={!form.name.trim()}
        >
          保存
        </Button>
      </DialogActions>
    </Dialog>
  );
};

/** Competitor form dialog */
const CompetitorDialog: React.FC<{
  open: boolean;
  competitor: BrandCompetitor | null;
  onClose: () => void;
  onSave: (competitor: BrandCompetitor) => void;
}> = ({ open, competitor, onClose, onSave }) => {
  const emptyCompetitor: BrandCompetitor = {
    id: '',
    name: '',
    positioning: '',
    strengths: [],
    weaknesses: [],
    keyProducts: [],
    contentStyle: '',
    commentHighlights: { praise: [], complaint: [] },
    swot: { S: '', W: '', O: '', T: '' },
  };

  const [form, setForm] = useState<BrandCompetitor>(emptyCompetitor);

  useEffect(() => {
    if (competitor) {
      setForm({ ...competitor });
    } else {
      setForm({ ...emptyCompetitor, id: `comp_${nanoid(8)}` });
    }
  }, [competitor, open]);

  const update = (field: string, value: unknown) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  return (
    <Dialog open={open} onClose={onClose} maxWidth="sm" fullWidth>
      <DialogTitle>{competitor ? '编辑竞品' : '添加竞品'}</DialogTitle>
      <DialogContent>
        <Stack spacing={2} sx={{ pt: 1 }}>
          <TextField
            label="竞品名称"
            value={form.name}
            onChange={(e) => update('name', e.target.value)}
            fullWidth
            required
          />
          <TextField
            label="定位"
            value={form.positioning}
            onChange={(e) => update('positioning', e.target.value)}
            fullWidth
            multiline
            minRows={2}
          />
          <TextField
            label="优势（每行一条）"
            value={(form.strengths || []).join('\n')}
            onChange={(e) =>
              update(
                'strengths',
                e.target.value.split('\n').filter(Boolean),
              )
            }
            fullWidth
            multiline
            minRows={3}
          />
          <TextField
            label="劣势（每行一条）"
            value={(form.weaknesses || []).join('\n')}
            onChange={(e) =>
              update(
                'weaknesses',
                e.target.value.split('\n').filter(Boolean),
              )
            }
            fullWidth
            multiline
            minRows={3}
          />
          <TextField
            label="内容风格"
            value={form.contentStyle}
            onChange={(e) => update('contentStyle', e.target.value)}
            fullWidth
          />
          <Typography variant="subtitle2">SWOT 分析</Typography>
          <TextField
            label="优势 (S)"
            value={form.swot.S}
            onChange={(e) => update('swot', { ...form.swot, S: e.target.value })}
            fullWidth
            multiline
            minRows={2}
          />
          <TextField
            label="劣势 (W)"
            value={form.swot.W}
            onChange={(e) => update('swot', { ...form.swot, W: e.target.value })}
            fullWidth
            multiline
            minRows={2}
          />
          <TextField
            label="机会 (O)"
            value={form.swot.O}
            onChange={(e) => update('swot', { ...form.swot, O: e.target.value })}
            fullWidth
            multiline
            minRows={2}
          />
          <TextField
            label="威胁 (T)"
            value={form.swot.T}
            onChange={(e) => update('swot', { ...form.swot, T: e.target.value })}
            fullWidth
            multiline
            minRows={2}
          />
        </Stack>
      </DialogContent>
      <DialogActions>
        <Button onClick={onClose}>取消</Button>
        <Button
          onClick={() => onSave(form)}
          variant="contained"
          disabled={!form.name.trim()}
        >
          保存
        </Button>
      </DialogActions>
    </Dialog>
  );
};

/** Keyword editor */
const KeywordEditor: React.FC<{
  title: string;
  words: string[];
  onAdd: (word: string) => void;
  onDelete: (index: number) => void;
}> = ({ title, words, onAdd, onDelete }) => {
  const [newWord, setNewWord] = useState('');

  const handleAdd = () => {
    const trimmed = newWord.trim();
    if (trimmed && !words.includes(trimmed)) {
      onAdd(trimmed);
      setNewWord('');
    }
  };

  return (
    <Box sx={{ mb: 1.5 }}>
      <Typography variant="body2" fontWeight={600} sx={{ mb: 0.5 }}>
        {title}
      </Typography>
      <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 0.5, mb: 1 }}>
        {words.map((word, i) => (
          <Chip
            key={`${word}-${i}`}
            label={word}
            size="small"
            onDelete={() => onDelete(i)}
          />
        ))}
        {words.length === 0 && (
          <Typography variant="body2" color="text.secondary">
            暂无
          </Typography>
        )}
      </Box>
      <Box sx={{ display: 'flex', gap: 1 }}>
        <TextField
          size="small"
          value={newWord}
          onChange={(e) => setNewWord(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') {
              e.preventDefault();
              handleAdd();
            }
          }}
          placeholder="输入关键词后回车"
          sx={{ flexGrow: 1 }}
        />
        <Button
          size="small"
          variant="outlined"
          onClick={handleAdd}
          disabled={!newWord.trim()}
        >
          添加
        </Button>
      </Box>
    </Box>
  );
};

/** Brand knowledge configuration page */
const BrandKnowledgePage: React.FC = () => {
  const brand = useCurrentBrand();
  const updateBrand = useBrandStore((s) => s.updateBrand);

  // Local form state
  const [brandStory, setBrandStory] = useState('');
  const [visualStyle, setVisualStyle] = useState('');
  const [tone, setTone] = useState('');
  const [keywords, setKeywords] = useState<BrandKeywords>({
    brandWords: [],
    categoryWords: [],
    sceneWords: [],
    audienceWords: [],
  });
  const [contentGuidelines, setContentGuidelines] = useState<ContentGuidelines>({
    do: [],
    dont: [],
  });
  const [products, setProducts] = useState<Product[]>([]);
  const [competitors, setCompetitors] = useState<BrandCompetitor[]>([]);

  // Dialogs
  const [productDialogOpen, setProductDialogOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [competitorDialogOpen, setCompetitorDialogOpen] = useState(false);
  const [editingCompetitor, setEditingCompetitor] = useState<BrandCompetitor | null>(null);

  // Snackbar
  const [snackbar, setSnackbar] = useState<{
    open: boolean;
    message: string;
    severity: 'success' | 'error';
  }>({ open: false, message: '', severity: 'success' });

  // Load brand config into local state
  useEffect(() => {
    if (brand) {
      setBrandStory(brand.config?.brandStory || '');
      setVisualStyle(brand.config?.visualStyle || '');
      setTone(brand.config?.tone || '');
      setKeywords(
        brand.config?.keywords || {
          brandWords: [],
          categoryWords: [],
          sceneWords: [],
          audienceWords: [],
        },
      );
      setContentGuidelines(
        brand.config?.contentGuidelines || { do: [], dont: [] },
      );
      setProducts(brand.config?.products || []);
      setCompetitors(brand.competitors || []);
    }
  }, [brand]);

  const handleSave = async () => {
    if (!brand) return;
    try {
      await updateBrand(brand.id, {
        config: {
          ...brand.config,
          products,
          brandStory,
          visualStyle,
          tone,
          keywords,
          contentGuidelines,
        },
        competitors,
      });
      setSnackbar({ open: true, message: '品牌知识库已保存', severity: 'success' });
    } catch (err) {
      setSnackbar({
        open: true,
        message: `保存失败：${err instanceof Error ? err.message : '未知错误'}`,
        severity: 'error',
      });
    }
  };

  // Keyword helpers
  const handleKeywordAdd = (category: keyof BrandKeywords, word: string) => {
    setKeywords((prev) => ({
      ...prev,
      [category]: [...prev[category], word],
    }));
  };

  const handleKeywordDelete = (category: keyof BrandKeywords, index: number) => {
    setKeywords((prev) => ({
      ...prev,
      [category]: prev[category].filter((_, i) => i !== index),
    }));
  };

  // Product helpers
  const handleProductSave = (product: Product) => {
    if (editingProduct) {
      setProducts((prev) =>
        prev.map((p) => (p === editingProduct ? product : p)),
      );
    } else {
      setProducts((prev) => [...prev, product]);
    }
    setProductDialogOpen(false);
    setEditingProduct(null);
  };

  const handleProductDelete = (index: number) => {
    setProducts((prev) => prev.filter((_, i) => i !== index));
  };

  // Competitor helpers
  const handleCompetitorSave = (competitor: BrandCompetitor) => {
    if (editingCompetitor) {
      setCompetitors((prev) =>
        prev.map((c) => (c.id === editingCompetitor.id ? competitor : c)),
      );
    } else {
      setCompetitors((prev) => [...prev, competitor]);
    }
    setCompetitorDialogOpen(false);
    setEditingCompetitor(null);
  };

  const handleCompetitorDelete = (id: string) => {
    setCompetitors((prev) => prev.filter((c) => c.id !== id));
  };

  if (!brand) {
    return (
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          height: '100%',
        }}
      >
        <Typography color="text.secondary">请先选择品牌</Typography>
      </Box>
    );
  }

  return (
    <Box>
      {/* Header */}
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          mb: 3,
        }}
      >
        <Box>
          <Typography variant="h5" fontWeight={700}>
            {brand.name} — 品牌知识库
          </Typography>
          <Typography variant="body2" color="text.secondary">
            配置品牌故事、产品线、竞品等信息，AI 分析将基于这些知识生成更精准的洞察
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<SaveIcon />}
          onClick={handleSave}
        >
          保存所有修改
        </Button>
      </Box>

      <Stack spacing={2.5}>
        {/* 1. Products */}
        <Accordion defaultExpanded>
          <AccordionSummary expandIcon={<ExpandMoreIcon />}>
            <Typography fontWeight={600}>
              产品线（{products.length} 个产品）
            </Typography>
          </AccordionSummary>
          <AccordionDetails>
            <Stack spacing={1.5}>
              {products.map((product, i) => (
                <Paper
                  key={i}
                  variant="outlined"
                  sx={{ p: 2, display: 'flex', alignItems: 'center', gap: 2 }}
                >
                  <Box sx={{ flexGrow: 1 }}>
                    <Typography variant="body2" fontWeight={600}>
                      {product.name}
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                      SKU: {product.sku || '—'} | ¥{product.price}/{product.unit}
                    </Typography>
                    {(product.sellingPoints || []).length > 0 && (
                      <Box sx={{ display: 'flex', gap: 0.5, mt: 0.5, flexWrap: 'wrap' }}>
                        {product.sellingPoints.map((sp) => (
                          <Chip key={sp} label={sp} size="small" variant="outlined" />
                        ))}
                      </Box>
                    )}
                  </Box>
                  <Tooltip title="编辑">
                    <IconButton
                      size="small"
                      onClick={() => {
                        setEditingProduct(product);
                        setProductDialogOpen(true);
                      }}
                    >
                      <EditIcon fontSize="small" />
                    </IconButton>
                  </Tooltip>
                  <Tooltip title="删除">
                    <IconButton
                      size="small"
                      onClick={() => handleProductDelete(i)}
                      color="error"
                    >
                      <DeleteIcon fontSize="small" />
                    </IconButton>
                  </Tooltip>
                </Paper>
              ))}
              <Button
                startIcon={<AddIcon />}
                onClick={() => {
                  setEditingProduct(null);
                  setProductDialogOpen(true);
                }}
                variant="outlined"
                size="small"
              >
                添加产品
              </Button>
            </Stack>
          </AccordionDetails>
        </Accordion>

        {/* 2. Brand Story */}
        <Accordion defaultExpanded>
          <AccordionSummary expandIcon={<ExpandMoreIcon />}>
            <Typography fontWeight={600}>品牌故事与视觉</Typography>
          </AccordionSummary>
          <AccordionDetails>
            <Stack spacing={2}>
              <TextField
                label="品牌故事"
                value={brandStory}
                onChange={(e) => setBrandStory(e.target.value)}
                multiline
                minRows={3}
                maxRows={8}
                fullWidth
                placeholder="描述品牌的历史、使命、核心理念..."
              />
              <TextField
                label="视觉风格"
                value={visualStyle}
                onChange={(e) => setVisualStyle(e.target.value)}
                multiline
                minRows={2}
                maxRows={4}
                fullWidth
                placeholder="描述品牌的视觉风格，如：简约现代、温暖自然、高端奢华..."
              />
              <TextField
                label="语调 (Tone)"
                value={tone}
                onChange={(e) => setTone(e.target.value)}
                multiline
                minRows={2}
                maxRows={4}
                fullWidth
                placeholder="描述品牌的内容语调，如：专业亲和、轻松有趣、温暖治愈..."
              />
            </Stack>
          </AccordionDetails>
        </Accordion>

        {/* 3. Keywords */}
        <Accordion defaultExpanded>
          <AccordionSummary expandIcon={<ExpandMoreIcon />}>
            <Typography fontWeight={600}>品牌关键词</Typography>
          </AccordionSummary>
          <AccordionDetails>
            <Grid container spacing={2}>
              <Grid item xs={12} md={6}>
                <KeywordEditor
                  title="品牌词"
                  words={keywords.brandWords}
                  onAdd={(w) => handleKeywordAdd('brandWords', w)}
                  onDelete={(i) => handleKeywordDelete('brandWords', i)}
                />
              </Grid>
              <Grid item xs={12} md={6}>
                <KeywordEditor
                  title="品类词"
                  words={keywords.categoryWords}
                  onAdd={(w) => handleKeywordAdd('categoryWords', w)}
                  onDelete={(i) => handleKeywordDelete('categoryWords', i)}
                />
              </Grid>
              <Grid item xs={12} md={6}>
                <KeywordEditor
                  title="场景词"
                  words={keywords.sceneWords}
                  onAdd={(w) => handleKeywordAdd('sceneWords', w)}
                  onDelete={(i) => handleKeywordDelete('sceneWords', i)}
                />
              </Grid>
              <Grid item xs={12} md={6}>
                <KeywordEditor
                  title="人群词"
                  words={keywords.audienceWords}
                  onAdd={(w) => handleKeywordAdd('audienceWords', w)}
                  onDelete={(i) => handleKeywordDelete('audienceWords', i)}
                />
              </Grid>
            </Grid>
          </AccordionDetails>
        </Accordion>

        {/* 4. Content Guidelines */}
        <Accordion>
          <AccordionSummary expandIcon={<ExpandMoreIcon />}>
            <Typography fontWeight={600}>内容指南</Typography>
          </AccordionSummary>
          <AccordionDetails>
            <Stack spacing={2}>
              <TextField
                label="✅ 应该做 (Do) — 每行一条"
                value={(contentGuidelines.do || []).join('\n')}
                onChange={(e) =>
                  setContentGuidelines((prev) => ({
                    ...prev,
                    do: e.target.value.split('\n').filter(Boolean),
                  }))
                }
                multiline
                minRows={4}
                maxRows={8}
                fullWidth
                placeholder="使用真实用户场景描述&#10;引用具体数据支撑观点&#10;保持品牌调性一致性"
              />
              <TextField
                label="❌ 不应该做 (Don't) — 每行一条"
                value={(contentGuidelines.dont || []).join('\n')}
                onChange={(e) =>
                  setContentGuidelines((prev) => ({
                    ...prev,
                    dont: e.target.value.split('\n').filter(Boolean),
                  }))
                }
                multiline
                minRows={4}
                maxRows={8}
                fullWidth
                placeholder="夸大产品功效&#10;使用贬低竞品的语言&#10;忽略用户真实痛点"
              />
            </Stack>
          </AccordionDetails>
        </Accordion>

        {/* 5. Competitors */}
        <Accordion defaultExpanded>
          <AccordionSummary expandIcon={<ExpandMoreIcon />}>
            <Typography fontWeight={600}>
              竞品管理（{competitors.length} 个竞品）
            </Typography>
          </AccordionSummary>
          <AccordionDetails>
            <Stack spacing={1.5}>
              {competitors.map((comp) => (
                <Paper
                  key={comp.id}
                  variant="outlined"
                  sx={{ p: 2 }}
                >
                  <Box
                    sx={{
                      display: 'flex',
                      alignItems: 'flex-start',
                      justifyContent: 'space-between',
                    }}
                  >
                    <Box>
                      <Typography variant="body2" fontWeight={600}>
                        {comp.name}
                      </Typography>
                      <Typography variant="body2" color="text.secondary">
                        {comp.positioning || '未设置定位'}
                      </Typography>
                      {comp.strengths.length > 0 && (
                        <Box sx={{ display: 'flex', gap: 0.5, mt: 0.5, flexWrap: 'wrap' }}>
                          {comp.strengths.slice(0, 3).map((s) => (
                            <Chip
                              key={s}
                              label={s}
                              size="small"
                              color="success"
                              variant="outlined"
                            />
                          ))}
                        </Box>
                      )}
                    </Box>
                    <Box sx={{ display: 'flex', gap: 0.5 }}>
                      <Tooltip title="编辑">
                        <IconButton
                          size="small"
                          onClick={() => {
                            setEditingCompetitor(comp);
                            setCompetitorDialogOpen(true);
                          }}
                        >
                          <EditIcon fontSize="small" />
                        </IconButton>
                      </Tooltip>
                      <Tooltip title="删除">
                        <IconButton
                          size="small"
                          onClick={() => handleCompetitorDelete(comp.id)}
                          color="error"
                        >
                          <DeleteIcon fontSize="small" />
                        </IconButton>
                      </Tooltip>
                    </Box>
                  </Box>
                </Paper>
              ))}
              <Button
                startIcon={<AddIcon />}
                onClick={() => {
                  setEditingCompetitor(null);
                  setCompetitorDialogOpen(true);
                }}
                variant="outlined"
                size="small"
              >
                添加竞品
              </Button>
            </Stack>
          </AccordionDetails>
        </Accordion>
      </Stack>

      {/* Product dialog */}
      <ProductDialog
        open={productDialogOpen}
        product={editingProduct}
        onClose={() => {
          setProductDialogOpen(false);
          setEditingProduct(null);
        }}
        onSave={handleProductSave}
      />

      {/* Competitor dialog */}
      <CompetitorDialog
        open={competitorDialogOpen}
        competitor={editingCompetitor}
        onClose={() => {
          setCompetitorDialogOpen(false);
          setEditingCompetitor(null);
        }}
        onSave={handleCompetitorSave}
      />

      {/* Snackbar */}
      <Snackbar
        open={snackbar.open}
        autoHideDuration={3000}
        onClose={() => setSnackbar((prev) => ({ ...prev, open: false }))}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
      >
        <Alert
          severity={snackbar.severity}
          onClose={() => setSnackbar((prev) => ({ ...prev, open: false }))}
          variant="filled"
        >
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Box>
  );
};

export default BrandKnowledgePage;
