import { useMemo } from 'react';
import { useBrandStore } from '../stores/brandStore';
import type { Brand } from '../types/brand';

/**
 * Hook to get the currently active brand.
 * Returns null if no brand is selected.
 */
export function useCurrentBrand(): Brand | null {
  const brands = useBrandStore((s) => s.brands);
  const currentBrandId = useBrandStore((s) => s.currentBrandId);

  return useMemo(() => {
    if (!currentBrandId) return null;
    return brands.find((b) => b.id === currentBrandId) || null;
  }, [brands, currentBrandId]);
}
